contracts/APICredits.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {BinaryIMTData} from "@zk-kit/imt.sol/internal/InternalBinaryIMT.sol";
import {Poseidon2IMT} from "./Poseidon2IMT.sol";

/**
 * @title APICredits
 * @notice Private anonymous LLM API credits using ZK proofs + ERC-20 token staking.
 *
 * Token-agnostic and forkable — accepts any ERC-20 set at deploy time.
 * PRICE_PER_CREDIT is a static constructor param.
 *
 * Uses zk-kit imt.sol's BinaryIMTData struct with a Poseidon2 hash adapter
 * (Poseidon2IMT library). This matches the Noir circuit's binary_merkle_root
 * exactly — every level hashes two children, using precomputed zero hashes
 * for empty subtrees.
 *
 * Economic model:
 *   stake()    → tokens sit in stakedBalance (user CAN withdraw)
 *   register() → tokens move to serverClaimable (user CANNOT touch again)
 *   api_call() → burns nullifier offchain (no token movement)
 */
contract APICredits is Ownable {
    using SafeERC20 for IERC20;
    using Poseidon2IMT for BinaryIMTData;

    // ─── Errors ───────────────────────────────────────────────
    error APICredits__ZeroAmount();
    error APICredits__InsufficientStake();
    error APICredits__CommitmentAlreadyUsed(uint256 commitment);
    error APICredits__EmptyTree();

    // ─── Constants ────────────────────────────────────────────
    uint256 public constant MAX_DEPTH = 16; // supports up to 65536 leaves

    // ─── Immutables ───────────────────────────────────────────
    IERC20 public immutable paymentToken;

    // ─── Mutable pricing ─────────────────────────────────────
    uint256 public pricePerCredit;

    // ─── State ────────────────────────────────────────────────
    mapping(address => uint256) public stakedBalance;

    // Revenue recipient — receives CLAWD immediately on every registration
    address public claimRecipient;

    // Kept for backwards-compat view calls; always 0 with auto-forward
    uint256 public serverClaimable;

    // Incremental Merkle tree (imt.sol struct, Poseidon2 hashing)
    BinaryIMTData public tree;

    mapping(uint256 => bool) public commitmentUsed;

    // ─── Events ───────────────────────────────────────────────
    event Staked(address indexed user, uint256 amount, uint256 newBalance);
    event Unstaked(address indexed user, uint256 amount, uint256 newBalance);
    event CreditRegistered(
        address indexed user,
        uint256 indexed index,
        uint256 commitment,
        uint256 newStakedBalance
    );
    event NewLeaf(uint256 index, uint256 value);
    event ServerClaimed(address indexed to, uint256 amount);
    event ClaimRecipientUpdated(address indexed oldRecipient, address indexed newRecipient);

    // ─── Constructor ──────────────────────────────────────────
    constructor(address _paymentToken, uint256 _pricePerCredit, address _owner, address _claimRecipient) Ownable(_owner) {
        require(_claimRecipient != address(0), "zero claim recipient");
        paymentToken = IERC20(_paymentToken);
        pricePerCredit = _pricePerCredit;
        claimRecipient = _claimRecipient;

        // Initialize the imt.sol tree with Poseidon2 zero hashes
        tree.init(MAX_DEPTH);
    }

    // ─── User Functions ───────────────────────────────────────

    function stake(uint256 amount) external {
        if (amount == 0) revert APICredits__ZeroAmount();
        paymentToken.safeTransferFrom(msg.sender, address(this), amount);
        stakedBalance[msg.sender] += amount;
        emit Staked(msg.sender, amount, stakedBalance[msg.sender]);
    }

    function unstake(uint256 amount) external {
        if (amount == 0) revert APICredits__ZeroAmount();
        if (stakedBalance[msg.sender] < amount) revert APICredits__InsufficientStake();
        stakedBalance[msg.sender] -= amount;
        emit Unstaked(msg.sender, amount, stakedBalance[msg.sender]);
        paymentToken.safeTransfer(msg.sender, amount);
    }

    /**
     * @notice Pay tokens and register commitments in one transaction.
     * @dev All tokens go directly to serverClaimable — the caller (usually CLAWDRouter)
     *      is responsible for sending the correct amount. No pricePerCredit check here.
     * @param amount  Total tokens to pay
     * @param commitments  One commitment per credit
     */
    function stakeAndRegister(uint256 amount, uint256[] calldata commitments) external {
        if (amount == 0) revert APICredits__ZeroAmount();
        require(commitments.length > 0, "no commitments");
        require(amount >= pricePerCredit * commitments.length, "commitment count mismatch");

        // Transfer tokens directly to claimRecipient (Safe) — no accumulation
        paymentToken.safeTransferFrom(msg.sender, claimRecipient, amount);
        emit ServerClaimed(claimRecipient, amount);

        // Register each commitment (payment already forwarded)
        for (uint256 i = 0; i < commitments.length; i++) {
            _registerDirect(commitments[i]);
        }
    }

    function register(uint256 _commitment) external {
        if (stakedBalance[msg.sender] < pricePerCredit) revert APICredits__InsufficientStake();
        _register(_commitment);
    }

    function _register(uint256 _commitment) internal {
        if (stakedBalance[msg.sender] < pricePerCredit) revert APICredits__InsufficientStake();
        if (commitmentUsed[_commitment]) revert APICredits__CommitmentAlreadyUsed(_commitment);

        // Move tokens from user's staked balance directly to claimRecipient (Safe)
        stakedBalance[msg.sender] -= pricePerCredit;
        paymentToken.safeTransfer(claimRecipient, pricePerCredit);
        emit ServerClaimed(claimRecipient, pricePerCredit);

        commitmentUsed[_commitment] = true;
        _insertLeaf(_commitment);
    }

    /// @dev Register a commitment without balance checks (used by stakeAndRegister where payment is pre-handled)
    function _registerDirect(uint256 _commitment) internal {
        if (commitmentUsed[_commitment]) revert APICredits__CommitmentAlreadyUsed(_commitment);

        commitmentUsed[_commitment] = true;
        _insertLeaf(_commitment);
    }

    /// @dev Insert a leaf into the incremental Merkle tree
    function _insertLeaf(uint256 _commitment) internal {
        uint256 index = tree.numberOfLeaves;
        tree.insert(_commitment);

        emit NewLeaf(index, _commitment);
        emit CreditRegistered(msg.sender, index, _commitment, stakedBalance[msg.sender]);
    }

    // ─── Owner Functions ──────────────────────────────────────

    function claimServer(address to, uint256 amount) external onlyOwner {
        if (amount == 0) revert APICredits__ZeroAmount();
        if (amount > serverClaimable) revert APICredits__InsufficientStake();
        serverClaimable -= amount;
        emit ServerClaimed(to, amount);
        paymentToken.safeTransfer(to, amount);
    }

    /**
     * @notice Update the revenue recipient. Owner only.
     */
    function setClaimRecipient(address newRecipient) external onlyOwner {
        require(newRecipient != address(0), "zero address");
        emit ClaimRecipientUpdated(claimRecipient, newRecipient);
        claimRecipient = newRecipient;
    }

    /**
     * @notice Update the price per credit. Owner only.
     */
    function setPricePerCredit(uint256 newPrice) external onlyOwner {
        require(newPrice > 0, "zero price");
        pricePerCredit = newPrice;
    }

    // ─── View Functions ───────────────────────────────────────

    /// @notice Backwards-compatible view: returns (size, depth, root).
    function getTreeData()
        external
        view
        returns (uint256 size, uint256 treeDepth, uint256 treeRoot)
    {
        if (tree.numberOfLeaves == 0) revert APICredits__EmptyTree();
        return (tree.numberOfLeaves, tree.depth, tree.root);
    }

    /// @notice Alias for tree.numberOfLeaves (backwards compat).
    function treeSize() external view returns (uint256) {
        return tree.numberOfLeaves;
    }

    /// @notice Alias for tree.depth (backwards compat).
    function depth() external view returns (uint256) {
        return tree.depth;
    }

    /// @notice Alias for tree.root (backwards compat).
    function root() external view returns (uint256) {
        return tree.root;
    }

    function isCommitmentUsed(uint256 _commitment) external view returns (bool) {
        return commitmentUsed[_commitment];
    }

    /// @notice Returns the Poseidon2 zero hash at the given level.
    function getZeroHash(uint256 level) external view returns (uint256) {
        return tree.zeroes[level];
    }
}

contracts/CLAWDPricing.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {IUniswapV3Pool} from "./interfaces/IUniswapV3Pool.sol";
import {AggregatorV3Interface} from "./interfaces/AggregatorV3Interface.sol";
import {TickMath} from "./libraries/TickMath.sol";
import {FullMath} from "./libraries/FullMath.sol";

/**
 * @title CLAWDPricing
 * @notice Standalone TWAP oracle for CLAWD token pricing.
 *
 * Reads the WETH/CLAWD Uniswap v3 pool TWAP to determine CLAWD/ETH price,
 * then uses Chainlink ETH/USD (with owner-set fallback) to derive CLAWD/USD.
 *
 * Used by CLAWDRouter to compute how much CLAWD is needed per API credit.
 */
contract CLAWDPricing is Ownable {
    // ─── Errors ───────────────────────────────────────────────
    error CLAWDPricing__ZeroValue();
    error CLAWDPricing__ZeroPriceOracle();

    // ─── Constants ────────────────────────────────────────────
    uint32 public constant TWAP_WINDOW = 1800; // 30-minute TWAP

    // ─── Immutables ───────────────────────────────────────────
    IUniswapV3Pool public immutable uniswapPool;
    AggregatorV3Interface public immutable chainlinkEthUsd;

    // ─── State ────────────────────────────────────────────────
    /// @notice Target USD price per credit (18 decimals). Default: $0.10
    uint256 public creditPriceUSD = 0.05e18;

    /// @notice Fallback ETH/USD price if Chainlink is stale/unavailable (18 decimals)
    uint256 public ethUsdPrice = 1900e18;

    /// @notice Maximum age for Chainlink data before falling back (seconds)
    uint256 public chainlinkStalenessThreshold = 3600;

    // ─── Events ───────────────────────────────────────────────
    event CreditPriceUSDUpdated(uint256 oldPrice, uint256 newPrice);
    event EthUsdPriceUpdated(uint256 oldPrice, uint256 newPrice);

    // ─── Constructor ──────────────────────────────────────────
    constructor(
        address _uniswapPool,
        address _chainlinkEthUsd,
        address _owner
    ) Ownable(_owner) {
        uniswapPool = IUniswapV3Pool(_uniswapPool);
        chainlinkEthUsd = AggregatorV3Interface(_chainlinkEthUsd);
    }

    // ─── Oracle Functions ─────────────────────────────────────

    /**
     * @notice Get the ETH/USD price. Tries Chainlink first, falls back to owner-set price.
     * @return ETH price in USD with 18 decimals
     */
    function getEthUsdPrice() public view returns (uint256) {
        try chainlinkEthUsd.latestRoundData() returns (
            uint80, int256 price, uint256, uint256 updatedAt, uint80
        ) {
            if (price > 0 && block.timestamp - updatedAt < chainlinkStalenessThreshold) {
                // Chainlink ETH/USD has 8 decimals, scale to 18
                return uint256(price) * 1e10;
            }
        } catch {}
        return ethUsdPrice;
    }

    /**
     * @notice Get the TWAP tick from the Uniswap v3 pool over TWAP_WINDOW seconds.
     * @return arithmeticMeanTick The time-weighted average tick
     */
    function _getTwapTick() internal view returns (int24 arithmeticMeanTick) {
        uint32[] memory secondsAgos = new uint32[](2);
        secondsAgos[0] = TWAP_WINDOW;
        secondsAgos[1] = 0;

        (int56[] memory tickCumulatives, ) = uniswapPool.observe(secondsAgos);

        int56 tickCumulativesDelta = tickCumulatives[1] - tickCumulatives[0];

        arithmeticMeanTick = int24(tickCumulativesDelta / int56(int32(TWAP_WINDOW)));
        // Always round to negative infinity
        if (tickCumulativesDelta < 0 && (tickCumulativesDelta % int56(int32(TWAP_WINDOW)) != 0)) {
            arithmeticMeanTick--;
        }
    }

    /**
     * @notice Get CLAWD per ETH from the 30-minute TWAP.
     *
     * Pool: WETH (token0) / CLAWD (token1)
     * sqrtPriceX96 = sqrt(CLAWD/WETH) * 2^96
     * price = sqrtPriceX96^2 / 2^192 = CLAWD per WETH (both 18 dec)
     *
     * @return clawdPerEth CLAWD per ETH with 18 decimal precision
     */
    function getClawdPerEth() public view returns (uint256 clawdPerEth) {
        int24 twapTick = _getTwapTick();
        uint160 sqrtRatioX96 = TickMath.getSqrtRatioAtTick(twapTick);

        // Split: sqrtRatioX96^2 / 2^192 scaled to 18 decimals
        // step1 = sqrtRatioX96^2 / 2^64
        uint256 ratioX128 = FullMath.mulDiv(
            uint256(sqrtRatioX96),
            uint256(sqrtRatioX96),
            1 << 64
        );
        // clawdPerEth = ratioX128 * 1e18 / 2^128
        clawdPerEth = FullMath.mulDiv(ratioX128, 1e18, 1 << 128);
    }

    /**
     * @notice Get CLAWD price in USD.
     * @return clawdUsd CLAWD price in USD with 18 decimal precision
     */
    function getClawdUsdPrice() public view returns (uint256 clawdUsd) {
        uint256 clawdPerEth = getClawdPerEth();
        uint256 ethUsd = getEthUsdPrice();
        if (clawdPerEth == 0) revert CLAWDPricing__ZeroPriceOracle();
        // clawdUsd = ethUsd / clawdPerEth (both 18 dec → result is 18 dec)
        clawdUsd = FullMath.mulDiv(ethUsd, 1e18, clawdPerEth);
    }

    /**
     * @notice Get the credit price in CLAWD tokens.
     *
     * priceInCLAWD = creditPriceUSD / clawdUsdPrice
     *              = creditPriceUSD * clawdPerEth / ethUsdPrice
     *
     * @return priceInCLAWD Amount of CLAWD (18 dec) required per credit
     */
    function getCreditPriceInCLAWD() public view returns (uint256 priceInCLAWD) {
        uint256 clawdPerEth = getClawdPerEth();
        uint256 ethUsd = getEthUsdPrice();

        if (clawdPerEth == 0 || ethUsd == 0) revert CLAWDPricing__ZeroPriceOracle();

        priceInCLAWD = FullMath.mulDiv(creditPriceUSD, clawdPerEth, ethUsd);
    }

    // ─── Owner Functions ──────────────────────────────────────

    /**
     * @notice Set the target USD price per credit. Owner only.
     * @param newPriceUSD New price in USD with 18 decimals (e.g. 0.10e18 = $0.10)
     */
    function setCreditPriceUSD(uint256 newPriceUSD) external onlyOwner {
        if (newPriceUSD == 0) revert CLAWDPricing__ZeroValue();
        emit CreditPriceUSDUpdated(creditPriceUSD, newPriceUSD);
        creditPriceUSD = newPriceUSD;
    }

    /**
     * @notice Set the fallback ETH/USD price (used when Chainlink is stale). Owner only.
     * @param newPrice ETH price in USD with 18 decimals
     */
    function setEthUsdPrice(uint256 newPrice) external onlyOwner {
        if (newPrice == 0) revert CLAWDPricing__ZeroValue();
        emit EthUsdPriceUpdated(ethUsdPrice, newPrice);
        ethUsdPrice = newPrice;
    }

    /**
     * @notice Set the Chainlink staleness threshold. Owner only.
     * @param newThreshold Seconds before Chainlink data is considered stale
     */
    function setChainlinkStalenessThreshold(uint256 newThreshold) external onlyOwner {
        chainlinkStalenessThreshold = newThreshold;
    }

    // ─── View Helpers ─────────────────────────────────────────

    /**
     * @notice Returns all oracle data in one call for frontend display.
     */
    function getOracleData()
        external
        view
        returns (
            uint256 clawdPerEth,
            uint256 ethUsd,
            uint256 pricePerCreditCLAWD,
            uint256 usdPerCredit,
            uint256 clawdUsd
        )
    {
        clawdPerEth = getClawdPerEth();
        ethUsd = getEthUsdPrice();
        pricePerCreditCLAWD = getCreditPriceInCLAWD();
        usdPerCredit = creditPriceUSD;
        clawdUsd = getClawdUsdPrice();
    }
}

contracts/CLAWDRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {ISwapRouter} from "./interfaces/ISwapRouter.sol";
import {IWETH} from "./interfaces/IWETH.sol";

interface IAPICredits {
    function stakeAndRegister(uint256 amount, uint256[] calldata commitments) external;
    function paymentToken() external view returns (IERC20);
    function pricePerCredit() external view returns (uint256);
}

interface ICLAWDPricing {
    function getCreditPriceInCLAWD() external view returns (uint256);
    function getOracleData() external view returns (
        uint256 clawdPerEth,
        uint256 ethUsd,
        uint256 pricePerCreditCLAWD,
        uint256 usdPerCredit,
        uint256 clawdUsd
    );
}

/**
 * @title CLAWDRouter
 * @notice Payment router for ZK API Credits.
 *
 * Accepts CLAWD directly, ETH, or USDC. Non-CLAWD payments are swapped to CLAWD
 * via Uniswap v3 before calling APICredits.stakeAndRegister().
 *
 * Uses CLAWDPricing for TWAP-based price discovery.
 */
contract CLAWDRouter is Ownable {
    using SafeERC20 for IERC20;

    // ─── Errors ───────────────────────────────────────────────
    error CLAWDRouter__ZeroCommitments();
    error CLAWDRouter__InsufficientOutput();
    error CLAWDRouter__ETHTransferFailed();
    error CLAWDRouter__NothingToRefund();

    // ─── Immutables ───────────────────────────────────────────
    IAPICredits public immutable apiCredits;
    ICLAWDPricing public immutable pricing;
    IERC20 public immutable clawdToken;
    IERC20 public immutable usdc;
    IWETH public immutable weth;
    ISwapRouter public immutable swapRouter;

    // ─── Constants ────────────────────────────────────────────
    uint24 public constant CLAWD_WETH_FEE = 10000; // 1% fee tier
    uint24 public constant USDC_WETH_FEE = 500;    // 0.05% fee tier (standard)

    // ─── Events ───────────────────────────────────────────────
    event CreditsPurchasedWithCLAWD(
        address indexed buyer,
        uint256 numCredits,
        uint256 clawdSpent
    );
    event CreditsPurchasedWithETH(
        address indexed buyer,
        uint256 numCredits,
        uint256 ethSpent,
        uint256 clawdAcquired
    );
    event CreditsPurchasedWithUSDC(
        address indexed buyer,
        uint256 numCredits,
        uint256 usdcSpent,
        uint256 clawdAcquired
    );

    // ─── Constructor ──────────────────────────────────────────
    constructor(
        address _apiCredits,
        address _pricing,
        address _clawdToken,
        address _usdc,
        address _weth,
        address _swapRouter,
        address _owner
    ) Ownable(_owner) {
        apiCredits = IAPICredits(_apiCredits);
        pricing = ICLAWDPricing(_pricing);
        clawdToken = IERC20(_clawdToken);
        usdc = IERC20(_usdc);
        weth = IWETH(_weth);
        swapRouter = ISwapRouter(_swapRouter);

        // Pre-approve APICredits to spend CLAWD from this contract
        IERC20(_clawdToken).approve(_apiCredits, type(uint256).max);
    }

    // ─── Buy with CLAWD ───────────────────────────────────────

    /**
     * @notice Buy credits by paying CLAWD directly.
     * @param commitments ZK commitments (one per credit)
     * @param maxCLAWD Maximum CLAWD willing to spend (slippage protection)
     */
    function buyWithCLAWD(
        uint256[] calldata commitments,
        uint256 maxCLAWD
    ) external {
        if (commitments.length == 0) revert CLAWDRouter__ZeroCommitments();

        uint256 totalCLAWD = pricing.getCreditPriceInCLAWD() * commitments.length;
        if (maxCLAWD < totalCLAWD) revert CLAWDRouter__InsufficientOutput();

        // Pull CLAWD from user
        clawdToken.safeTransferFrom(msg.sender, address(this), totalCLAWD);

        // Approve APICredits to pull CLAWD, then register
        clawdToken.approve(address(apiCredits), totalCLAWD);
        apiCredits.stakeAndRegister(totalCLAWD, commitments);

        emit CreditsPurchasedWithCLAWD(msg.sender, commitments.length, totalCLAWD);
    }

    // ─── Buy with ETH ─────────────────────────────────────────

    /**
     * @notice Buy credits by paying ETH. Swaps ETH → WETH → CLAWD via Uniswap.
     * @param commitments ZK commitments (one per credit)
     * @param minCLAWDOut Minimum CLAWD to receive from swap (slippage protection)
     */
    function buyWithETH(
        uint256[] calldata commitments,
        uint256 minCLAWDOut
    ) external payable {
        if (commitments.length == 0) revert CLAWDRouter__ZeroCommitments();

        uint256 totalCLAWD = pricing.getCreditPriceInCLAWD() * commitments.length;

        // Wrap ETH → WETH, then swap WETH → CLAWD
        IWETH(address(weth)).deposit{value: msg.value}();
        IERC20(address(weth)).approve(address(swapRouter), msg.value);
        uint256 clawdReceived = swapRouter.exactInputSingle(
            ISwapRouter.ExactInputSingleParams({
                tokenIn: address(weth),
                tokenOut: address(clawdToken),
                fee: CLAWD_WETH_FEE,
                recipient: address(this),
                amountIn: msg.value,
                amountOutMinimum: minCLAWDOut,
                sqrtPriceLimitX96: 0
            })
        );

        if (clawdReceived < totalCLAWD) revert CLAWDRouter__InsufficientOutput();

        // Approve APICredits to pull CLAWD from this router, then register
        clawdToken.approve(address(apiCredits), totalCLAWD);
        apiCredits.stakeAndRegister(totalCLAWD, commitments);

        // Refund excess CLAWD to buyer
        uint256 excess = clawdReceived - totalCLAWD;
        if (excess > 0) {
            clawdToken.safeTransfer(msg.sender, excess);
        }

        emit CreditsPurchasedWithETH(msg.sender, commitments.length, msg.value, clawdReceived);
    }

    // ─── Buy with USDC ────────────────────────────────────────

    /**
     * @notice Buy credits by paying USDC. Swaps USDC → WETH → CLAWD via Uniswap.
     * @param commitments ZK commitments (one per credit)
     * @param usdcAmount Amount of USDC to spend (6 decimals)
     * @param minCLAWDOut Minimum CLAWD to receive from swap (slippage protection)
     */
    function buyWithUSDC(
        uint256[] calldata commitments,
        uint256 usdcAmount,
        uint256 minCLAWDOut
    ) external {
        if (commitments.length == 0) revert CLAWDRouter__ZeroCommitments();

        uint256 totalCLAWD = pricing.getCreditPriceInCLAWD() * commitments.length;

        // Pull USDC from user
        usdc.safeTransferFrom(msg.sender, address(this), usdcAmount);

        // Approve router to spend USDC
        usdc.approve(address(swapRouter), usdcAmount);

        // Swap USDC → WETH (0.05% pool) → CLAWD (1% pool) via two-hop
        // For simplicity, use two exactInputSingle calls
        // Step 1: USDC → WETH
        uint256 wethReceived = swapRouter.exactInputSingle(
            ISwapRouter.ExactInputSingleParams({
                tokenIn: address(usdc),
                tokenOut: address(weth),
                fee: USDC_WETH_FEE,
                recipient: address(this),
                amountIn: usdcAmount,
                amountOutMinimum: 0, // protected by final minCLAWDOut
                sqrtPriceLimitX96: 0
            })
        );

        // Step 2: WETH → CLAWD
        IERC20(address(weth)).approve(address(swapRouter), wethReceived);
        uint256 clawdReceived = swapRouter.exactInputSingle(
            ISwapRouter.ExactInputSingleParams({
                tokenIn: address(weth),
                tokenOut: address(clawdToken),
                fee: CLAWD_WETH_FEE,
                recipient: address(this),
                amountIn: wethReceived,
                amountOutMinimum: minCLAWDOut,
                sqrtPriceLimitX96: 0
            })
        );

        if (clawdReceived < totalCLAWD) revert CLAWDRouter__InsufficientOutput();

        // Approve APICredits to pull CLAWD from this router, then register
        clawdToken.approve(address(apiCredits), totalCLAWD);
        apiCredits.stakeAndRegister(totalCLAWD, commitments);

        // Refund excess CLAWD to buyer
        uint256 excess = clawdReceived - totalCLAWD;
        if (excess > 0) {
            clawdToken.safeTransfer(msg.sender, excess);
        }

        emit CreditsPurchasedWithUSDC(msg.sender, commitments.length, usdcAmount, clawdReceived);
    }

    // ─── View Helpers ─────────────────────────────────────────

    /**
     * @notice Get the CLAWD amount needed for N credits (from TWAP oracle).
     * @dev Uses the live oracle price — same as what buy functions charge.
     */
    function quoteCredits(uint256 numCredits)
        external
        view
        returns (uint256 clawdNeeded, uint256 usdEquivalent)
    {
        clawdNeeded = pricing.getCreditPriceInCLAWD() * numCredits;
        (,,, uint256 usdPerCredit,) = pricing.getOracleData();
        usdEquivalent = usdPerCredit * numCredits;
    }

    // ─── Owner Functions ──────────────────────────────────────

    /**
     * @notice Rescue stuck tokens. Owner only.
     */
    function rescueTokens(address token, address to, uint256 amount) external onlyOwner {
        IERC20(token).safeTransfer(to, amount);
    }

    /**
     * @notice Accept ETH (for Uniswap refunds).
     */
    receive() external payable {}
}

